// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package v2

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// +genclient
// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object
// +deepequal-gen:private-method=true
// +kubebuilder:resource:categories={cilium},singular="ciliumpolicyquota",path="ciliumpolicyquotas",scope="Namespaced",shortName={cpq}
// +kubebuilder:printcolumn:JSONPath=".metadata.creationTimestamp",name="Age",type=date
// +kubebuilder:storageversion

// CiliumPolicyQuota is a Kubernetes third-party resource for defining policy quotas
// per namespace.
type CiliumPolicyQuota struct {
	// +deepequal-gen=false
	metav1.TypeMeta `json:",inline"`
	// +deepequal-gen=false
	metav1.ObjectMeta `json:"metadata"`

	// Spec is the desired policy quota specification.
	Spec CiliumPolicyQuotaSpec `json:"spec,omitempty"`
}

// +deepequal-gen=true

// CiliumPolicyQuotaSpec defines the policy quota specification.
type CiliumPolicyQuotaSpec struct {
	// MaxPoliciesPerNamespace is the maximum number of CiliumNetworkPolicy
	// resources allowed in a single namespace.
	//
	// +kubebuilder:validation:Minimum=1
	// +kubebuilder:validation:Required
	MaxPoliciesPerNamespace int32 `json:"maxPoliciesPerNamespace"`
}

// +k8s:deepcopy-gen:interfaces=k8s.io/apimachinery/pkg/runtime.Object

// CiliumPolicyQuotaList is a list of CiliumPolicyQuota objects.
type CiliumPolicyQuotaList struct {
	metav1.TypeMeta `json:",inline"`
	metav1.ListMeta `json:"metadata"`

	// Items is a list of CiliumPolicyQuota.
	Items []CiliumPolicyQuota `json:"items"`
}

// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var (
	log = logrus.WithFields(logrus.Fields{
		logfields.LogSubsys: "policy-quota",
	})
)

// PolicyQuotaController manages per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log                  logrus.FieldLogger
	cnpResource          resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	policyQuotaResource  resource.Resource[*cilium_v2.CiliumPolicyQuota]
	maxPerNamespace      int
	namespacePolicyCounts sync.Map // map[string]int - namespace to policy count
	mu                   sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	logger logrus.FieldLogger,
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	policyQuotaResource resource.Resource[*cilium_v2.CiliumPolicyQuota],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                 logger,
		cnpResource:         cnpResource,
		policyQuotaResource: policyQuotaResource,
		maxPerNamespace:     maxPerNamespace,
	}
}

// Run starts the controller loop that watches CiliumNetworkPolicy resources
// and tracks policy counts per namespace.
func (pc *PolicyQuotaController) Run(ctx context.Context) {
	pc.log.Info("Starting PolicyQuotaController")

	// Watch both CNP and PolicyQuota resources
	cnpEvents := pc.cnpResource.Events(ctx)
	quotaEvents := pc.policyQuotaResource.Events(ctx)

	for {
		select {
		case <-ctx.Done():
			pc.log.Info("Stopping PolicyQuotaController")
			return
		case event, ok := <-cnpEvents:
			if !ok {
				cnpEvents = nil
				break
			}
			pc.handleCNPEvent(event)
		case event, ok := <-quotaEvents:
			if !ok {
				quotaEvents = nil
				break
			}
			pc.handleQuotaEvent(event)
		}

		// Exit if both channels are closed
		if cnpEvents == nil && quotaEvents == nil {
			break
		}
	}
}

// handleCNPEvent processes events for CiliumNetworkPolicy resources.
func (pc *PolicyQuotaController) handleCNPEvent(event resource.Event[*cilium_v2.CiliumNetworkPolicy]) {
	defer event.Done(nil)

	if event.Kind == resource.Sync {
		pc.log.Debug("CNP resources synced")
		return
	}

	cnp := event.Object
	namespace := cnp.GetNamespace()

	switch event.Kind {
	case resource.Upsert:
		// Increment policy count for namespace
		pc.incrementNamespaceCount(namespace)
	case resource.Delete:
		// Decrement policy count for namespace
		pc.decrementNamespaceCount(namespace)
	}
}

// handleQuotaEvent processes events for CiliumPolicyQuota resources.
func (pc *PolicyQuotaController) handleQuotaEvent(event resource.Event[*cilium_v2.CiliumPolicyQuota]) {
	defer event.Done(nil)

	if event.Kind == resource.Sync {
		pc.log.Debug("PolicyQuota resources synced")
		return
	}

	quota := event.Object
	if quota == nil {
		return
	}

	pc.mu.Lock()
	if event.Kind == resource.Upsert {
		// Update max policies per namespace if quota is updated
		pc.maxPerNamespace = int(quota.Spec.MaxPoliciesPerNamespace)
		pc.log.WithField("maxPerNamespace", pc.maxPerNamespace).
			Debug("Updated maximum policies per namespace")
	}
	pc.mu.Unlock()
}

// CheckQuota checks if adding a new policy would exceed the quota for the given namespace.
func (pc *PolicyQuotaController) CheckQuota(namespace string) error {
	pc.mu.RLock()
	defer pc.mu.RUnlock()

	count, _ := pc.namespacePolicyCounts.LoadOrStore(namespace, 0)
	currentCount := count.(int)

	if currentCount >= pc.maxPerNamespace {
		return fmt.Errorf("policy quota exceeded for namespace %s: current=%d, max=%d",
			namespace, currentCount, pc.maxPerNamespace)
	}
	return nil
}

// incrementNamespaceCount increments the policy count for a namespace.
func (pc *PolicyQuotaController) incrementNamespaceCount(namespace string) {
	val, _ := pc.namespacePolicyCounts.LoadOrStore(namespace, 0)
	count := val.(int)
	pc.namespacePolicyCounts.Store(namespace, count+1)
	pc.log.WithFields(logrus.Fields{
		"namespace": namespace,
		"count":     count + 1,
	}).Debug("Incremented policy count")
}

// decrementNamespaceCount decrements the policy count for a namespace.
func (pc *PolicyQuotaController) decrementNamespaceCount(namespace string) {
	val, _ := pc.namespacePolicyCounts.LoadOrStore(namespace, 0)
	count := val.(int)
	if count > 0 {
		pc.namespacePolicyCounts.Store(namespace, count-1)
	}
	pc.log.WithFields(logrus.Fields{
		"namespace": namespace,
		"count":     count - 1,
	}).Debug("Decremented policy count")
}

// GetNamespacePolicyCount returns the current policy count for a namespace.
func (pc *PolicyQuotaController) GetNamespacePolicyCount(namespace string) int {
	val, exists := pc.namespacePolicyCounts.Load(namespace)
	if !exists {
		return 0
	}
	return val.(int)
}

