package quota

import (
	"context"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/policy/api"
)

// MockResource implements a mock of resource.Resource[T] for testing
type MockResource[T any] struct {
	events chan resource.Event[T]
}

func NewMockResource[T any]() *MockResource[T] {
	return &MockResource[T]{
		events: make(chan resource.Event[T], 100),
	}
}

func (m *MockResource[T]) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[T] {
	return m.events
}

func (m *MockResource[T]) Observe(ctx context.Context, next func(resource.Event[T]) error, complete func(error)) error {
	return nil
}

func (m *MockResource[T]) Store(ctx context.Context) (resource.Store[T], error) {
	return nil, nil
}

func (m *MockResource[T]) SendEvent(event resource.Event[T]) {
	select {
	case m.events <- event:
	default:
		// Channel full, discard
	}
}

// MockEvent implements resource.Event[T]
type MockEvent[T any] struct {
	kind   resource.EventKind
	object T
}

func (e *MockEvent[T]) Kind() resource.EventKind {
	return e.kind
}

func (e *MockEvent[T]) Object() T {
	return e.object
}

func (e *MockEvent[T]) Done(err error) {
	// No-op for mock
}

func TestPolicyQuotaController_CheckQuota(t *testing.T) {
	logger := logrus.WithFields(logrus.Fields{
		"test": t.Name(),
	})

	mockCNPResource := NewMockResource[*cilium_v2.CiliumNetworkPolicy]()
	mockQuotaResource := NewMockResource[*cilium_v2.CiliumPolicyQuota]()

	controller := NewPolicyQuotaController(
		logger,
		mockCNPResource,
		mockQuotaResource,
		5, // max 5 policies per namespace
	)

	// Test 1: No policies, check should pass
	err := controller.CheckQuota("default")
	assert.NoError(t, err, "CheckQuota should pass when under quota")

	// Test 2: Add some policies
	for i := 0; i < 5; i++ {
		controller.incrementNamespaceCount("default")
	}

	// Test 3: At quota, next check should fail
	err = controller.CheckQuota("default")
	assert.Error(t, err, "CheckQuota should fail when at quota")
	assert.Contains(t, err.Error(), "policy quota exceeded")

	// Test 4: Different namespace should be independent
	err = controller.CheckQuota("other-namespace")
	assert.NoError(t, err, "CheckQuota should pass for different namespace")

	// Test 5: Verify count
	assert.Equal(t, 5, controller.GetNamespacePolicyCount("default"))
	assert.Equal(t, 0, controller.GetNamespacePolicyCount("other-namespace"))
}

func TestPolicyQuotaController_IncrementDecrement(t *testing.T) {
	logger := logrus.WithFields(logrus.Fields{
		"test": t.Name(),
	})

	mockCNPResource := NewMockResource[*cilium_v2.CiliumNetworkPolicy]()
	mockQuotaResource := NewMockResource[*cilium_v2.CiliumPolicyQuota]()

	controller := NewPolicyQuotaController(
		logger,
		mockCNPResource,
		mockQuotaResource,
		10,
	)

	// Test increment
	controller.incrementNamespaceCount("ns1")
	assert.Equal(t, 1, controller.GetNamespacePolicyCount("ns1"))

	controller.incrementNamespaceCount("ns1")
	assert.Equal(t, 2, controller.GetNamespacePolicyCount("ns1"))

	// Test decrement
	controller.decrementNamespaceCount("ns1")
	assert.Equal(t, 1, controller.GetNamespacePolicyCount("ns1"))

	controller.decrementNamespaceCount("ns1")
	assert.Equal(t, 0, controller.GetNamespacePolicyCount("ns1"))

	// Test decrement below zero doesn't go negative
	controller.decrementNamespaceCount("ns1")
	assert.Equal(t, 0, controller.GetNamespacePolicyCount("ns1"))
}

func TestPolicyQuotaController_MultipleNamespaces(t *testing.T) {
	logger := logrus.WithFields(logrus.Fields{
		"test": t.Name(),
	})

	mockCNPResource := NewMockResource[*cilium_v2.CiliumNetworkPolicy]()
	mockQuotaResource := NewMockResource[*cilium_v2.CiliumPolicyQuota]()

	controller := NewPolicyQuotaController(
		logger,
		mockCNPResource,
		mockQuotaResource,
		3,
	)

	// Add policies to multiple namespaces
	for i := 0; i < 3; i++ {
		controller.incrementNamespaceCount("ns1")
		controller.incrementNamespaceCount("ns2")
		controller.incrementNamespaceCount("ns3")
	}

	// Each namespace should have 3 policies
	assert.Equal(t, 3, controller.GetNamespacePolicyCount("ns1"))
	assert.Equal(t, 3, controller.GetNamespacePolicyCount("ns2"))
	assert.Equal(t, 3, controller.GetNamespacePolicyCount("ns3"))

	// All should be at quota
	assert.Error(t, controller.CheckQuota("ns1"))
	assert.Error(t, controller.CheckQuota("ns2"))
	assert.Error(t, controller.CheckQuota("ns3"))
}

func TestPolicyQuotaController_RunWithEvents(t *testing.T) {
	logger := logrus.WithFields(logrus.Fields{
		"test": t.Name(),
	})

	mockCNPResource := NewMockResource[*cilium_v2.CiliumNetworkPolicy]()
	mockQuotaResource := NewMockResource[*cilium_v2.CiliumPolicyQuota]()

	controller := NewPolicyQuotaController(
		logger,
		mockCNPResource,
		mockQuotaResource,
		2,
	)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Create test CNP objects
	cnp1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-1",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-2",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	// Start controller in a goroutine
	go controller.Run(ctx)

	// Send Sync event for CNPs
	mockCNPResource.SendEvent(&MockEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind: resource.Sync,
	})

	// Send Sync event for Quota
	mockQuotaResource.SendEvent(&MockEvent[*cilium_v2.CiliumPolicyQuota]{
		kind: resource.Sync,
	})

	// Send Upsert events for policies
	mockCNPResource.SendEvent(&MockEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Upsert,
		object: cnp1,
	})

	mockCNPResource.SendEvent(&MockEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Upsert,
		object: cnp2,
	})

	// Give controller time to process events
	// In a real test, we'd use a sync mechanism

	// Verify counts were updated
	assert.Equal(t, 2, controller.GetNamespacePolicyCount("default"))

	// Test that quota is now exceeded
	err := controller.CheckQuota("default")
	require.Error(t, err)
	assert.Contains(t, err.Error(), "policy quota exceeded")

	// Send Delete event
	mockCNPResource.SendEvent(&MockEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Delete,
		object: cnp1,
	})

	// Verify count was decremented
	assert.Equal(t, 1, controller.GetNamespacePolicyCount("default"))

	// Quota check should now pass
	err = controller.CheckQuota("default")
	assert.NoError(t, err)
}

func TestCiliumPolicyQuota_DeepCopy(t *testing.T) {
	original := &cilium_v2.CiliumPolicyQuota{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-quota",
			Namespace: "default",
		},
		Spec: cilium_v2.CiliumPolicyQuotaSpec{
			MaxPoliciesPerNamespace: 10,
		},
	}

	// Test DeepCopy
	copied := original.DeepCopy()
	assert.Equal(t, original.Name, copied.Name)
	assert.Equal(t, original.Spec.MaxPoliciesPerNamespace, copied.Spec.MaxPoliciesPerNamespace)

	// Modify copy and verify original is unchanged
	copied.Spec.MaxPoliciesPerNamespace = 20
	assert.Equal(t, int32(10), original.Spec.MaxPoliciesPerNamespace)
	assert.Equal(t, int32(20), copied.Spec.MaxPoliciesPerNamespace)
}

